PyTypeObject* DoInitWrapperHUD(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperHUDType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperHUDPyMethodDefs;
	PyType->tp_getset = FUPyWrapperHUDGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperHUD(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(AHUD::StaticClass(), DoInitWrapperHUD);
}

FUPyWrapperHUD* UPyIsHUD(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperHUDType))
	{
		return (FUPyWrapperHUD*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, AHUD*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperHUD* PyHUD = UPyIsHUD(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyHUD))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyHUD->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'AHUD'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
